import torch
import torch.nn as nn
import torch.nn.functional as F


class ReLUSAE(nn.Module):
    """Standard SAE with ReLU activations and L1 sparsity penalty."""

    def __init__(self, d_model: int, d_sae: int):
        super().__init__()
        self.d_model = d_model
        self.d_sae = d_sae
        self.b_pre = nn.Parameter(torch.zeros(d_model))
        self.W_enc = nn.Parameter(torch.nn.init.kaiming_uniform_(torch.empty(d_sae, d_model)))
        self.b_enc = nn.Parameter(torch.zeros(d_sae))
        self.W_dec = nn.Parameter(torch.nn.init.kaiming_uniform_(torch.empty(d_model, d_sae)))

    def encode(self, x: torch.Tensor) -> torch.Tensor:
        return F.relu((x - self.b_pre) @ self.W_enc.T + self.b_enc)

    def decode(self, f: torch.Tensor) -> torch.Tensor:
        return f @ self.W_dec.T + self.b_pre

    def forward(self, x: torch.Tensor) -> dict:
        f = self.encode(x)
        x_hat = self.decode(f)
        return {"features": f, "reconstruction": x_hat}

    def loss(self, x: torch.Tensor, l1_coeff: float = 0.001) -> torch.Tensor:
        out = self.forward(x)
        recon_loss = F.mse_loss(out["reconstruction"], x)
        sparsity_loss = out["features"].abs().mean()
        return recon_loss + l1_coeff * sparsity_loss

    @torch.no_grad()
    def normalise_decoder(self):
        """Constrain decoder columns to unit norm after each gradient step."""
        norms = self.W_dec.norm(dim=0, keepdim=True).clamp(min=1.0)
        self.W_dec.data /= norms

import torch
import torch.nn as nn
import torch.nn.functional as F


class TopKSAE(nn.Module):
    """SAE with TopK hard sparsity — exactly K features active per token."""

    def __init__(self, d_model: int, d_sae: int, k: int):
        super().__init__()
        self.k = k
        self.b_pre = nn.Parameter(torch.zeros(d_model))
        self.W_enc = nn.Parameter(torch.nn.init.kaiming_uniform_(torch.empty(d_sae, d_model)))
        self.b_enc = nn.Parameter(torch.zeros(d_sae))
        self.W_dec = nn.Parameter(torch.nn.init.kaiming_uniform_(torch.empty(d_model, d_sae)))

    def encode(self, x: torch.Tensor) -> tuple[torch.Tensor, torch.Tensor]:
        pre_act = (x - self.b_pre) @ self.W_enc.T + self.b_enc
        # Keep only the top-K activations; zero the rest
        topk_vals, topk_idx = pre_act.topk(self.k, dim=-1)
        sparse = torch.zeros_like(pre_act)
        sparse.scatter_(-1, topk_idx, F.relu(topk_vals))
        return sparse, pre_act

    def decode(self, f: torch.Tensor) -> torch.Tensor:
        return f @ self.W_dec.T + self.b_pre

    def forward(self, x: torch.Tensor) -> dict:
        f, pre_act = self.encode(x)
        x_hat = self.decode(f)
        return {"features": f, "pre_act": pre_act, "reconstruction": x_hat}

    def loss(self, x: torch.Tensor) -> torch.Tensor:
        out = self.forward(x)
        return F.mse_loss(out["reconstruction"], x)

    @torch.no_grad()
    def normalise_decoder(self):
        norms = self.W_dec.norm(dim=0, keepdim=True).clamp(min=1.0)
        self.W_dec.data /= norms
